import sys
from collections import deque

input = sys.stdin.readline

def solve():
    n, m = map(int, input().split())
    grid = []
    lab = (0, 0)
    for i in range(n):
        row = input().strip()
        grid.append(list(row))
        for j in range(len(row)):
            if row[j] == 'L':
                lab = (i, j)

    # Directions: R=0, D=1, L=2, U=3
    dr = [0, 1, 0, -1]
    dc = [1, 0, -1, 0]

    # For each cell and each command d, count[cell][d] = number of free neighbors in directions != d
    # remaining[cell][d] = number of non-forceable free neighbors in directions != d

    count = [[0] * 4 for _ in range(n * m)]
    remaining = [[0] * 4 for _ in range(n * m)]
    forceable = [False] * (n * m)

    def idx(r, c):
        return r * m + c

    # Precompute for each cell, free neighbors in each direction
    for r in range(n):
        for c in range(m):
            if grid[r][c] == '#':
                continue
            cell = idx(r, c)
            for d in range(4):
                nr, nc = r + dr[d], c + dc[d]
                if 0 <= nr < n and 0 <= nc < m and grid[nr][nc] != '#':
                    # neighbor in direction d is free
                    # this contributes to count[cell][cmd] for all cmd != d
                    for cmd in range(4):
                        if cmd != d:
                            count[cell][cmd] += 1
                            remaining[cell][cmd] += 1

    queue = deque()

    # Lab is forceable
    lr, lc = lab
    forceable[idx(lr, lc)] = True
    queue.append((lr, lc))

    while queue:
        vr, vc = queue.popleft()
        v = idx(vr, vc)

        # v became forceable
        # For each direction dir, check if there's a neighbor c such that v is in direction dir from c
        # i.e., c = v - direction dir => c is at (vr - dr[dir], vc - dc[dir])
        for dir in range(4):
            cr, cc = vr - dr[dir], vc - dc[dir]
            if 0 <= cr < n and 0 <= cc < m and grid[cr][cc] != '#':
                c = idx(cr, cc)
                if forceable[c]:
                    continue
                # v is in direction dir from c
                # For all commands d != dir, decrement remaining[c][d]
                for d in range(4):
                    if d != dir:
                        remaining[c][d] -= 1
                        if remaining[c][d] == 0 and count[c][d] > 0:
                            if not forceable[c]:
                                forceable[c] = True
                                queue.append((cr, cc))

    # Build output
    result = []
    for r in range(n):
        row = []
        for c in range(m):
            if grid[r][c] == '#':
                row.append('#')
            elif grid[r][c] == 'L':
                row.append('L')
            elif forceable[idx(r, c)]:
                row.append('+')
            else:
                row.append('.')
        result.append(''.join(row))

    print('\n'.join(result))

t = int(input())
for _ in range(t):
    solve()

